import React, { useState, useEffect } from "react";

const API = "http://localhost:3001";

/* ── Toast helper ──────────────────────────────────────────────────────────── */
function Toast({ toasts }) {
  return (
    <div className="toast-container">
      {toasts.map(t => (
        <div key={t.id} className={`toast toast-${t.type}${t.exit ? " exit" : ""}`}>
          <span style={{ fontSize: 18 }}>{t.type === "success" ? "✅" : "❌"}</span>
          <span>{t.msg}</span>
        </div>
      ))}
    </div>
  );
}

export default function User({ username, onLogout }) {
  const [toasts,    setToasts]   = useState([]);
  const [loading,   setLoading]  = useState({ good: false, bad: false });
  const [stats,     setStats]    = useState({ good: 0, bad: 0, total: 0 });
  const [weight,    setWeight]   = useState(null);
  const [health,    setHealth]   = useState(null);
  const [version,   setVersion]  = useState("unknown");

  const addToast = (msg, type = "success") => {
    const id = Date.now();
    setToasts(p => [...p, { id, msg, type }]);
    setTimeout(() => setToasts(p => p.filter(t => t.id !== id)), 3500);
  };

  const loadData = async () => {
    try {
      const [sRes, wRes, hRes] = await Promise.all([
        fetch(`${API}/stats`),
        fetch(`${API}/weight`),
        fetch(`${API}/health`),
      ]);
      const [s, w, h] = await Promise.all([sRes.json(), wRes.json(), hRes.json()]);
      setStats(s);
      setWeight(w.weight);
      setHealth(h.status);
      setVersion(h.version || "1.0.0");
    } catch {
      /* backend offline */
    }
  };

  useEffect(() => { loadData(); }, []);

  const sendFeedback = async (type) => {
    setLoading(p => ({ ...p, [type]: true }));
    try {
      const res  = await fetch(`${API}/feedback`, {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body:    JSON.stringify({ type }),
      });
      const data = await res.json();
      if (data.feedback) setStats(data.feedback);
      addToast(
        type === "good" ? "Thanks for the positive feedback! 🎉" : "Feedback noted — we'll improve! 🔧",
        "success",
      );
    } catch {
      addToast("Failed to send feedback. Please try again.", "error");
    } finally {
      setLoading(p => ({ ...p, [type]: false }));
    }
  };

  const total    = stats.good + stats.bad;
  const goodPct  = total ? Math.round((stats.good / total) * 100) : 0;
  const badPct   = total ? Math.round((stats.bad / total) * 100) : 0;

  return (
    <>
      <Toast toasts={toasts} />

      <div style={styles.page}>
        {/* Header */}
        <header style={styles.header} className="card">
          <div style={styles.headerLeft}>
            <span style={styles.logoIcon}>🐦</span>
            <div>
              <div style={styles.logoText}>Canary Dashboard</div>
              <div style={styles.headerSub}>User View</div>
            </div>
          </div>
          <div style={styles.headerRight}>
            <div className="badge badge-green"><span className="dot dot-green" /> Live</div>
            {weight !== null && (
              <div className="badge badge-blue">Canary: {weight}%</div>
            )}
            <div style={styles.userPill}>
              <span>👤</span>
              <span>{username || "User"}</span>
            </div>
            <button id="logout-btn" className="btn btn-ghost btn-sm" onClick={onLogout}>
              Sign out
            </button>
          </div>
        </header>

        {/* Main */}
        <main style={styles.main}>

          {/* Welcome banner */}
          <div className="card anim-fade-up" style={styles.welcomeCard}>
            <div style={styles.welcomeLeft}>
              <div style={styles.welcomeIcon}>🚀</div>
              <div>
                <h1 style={styles.welcomeTitle}>Welcome, {username || "User"}!</h1>
                <p style={styles.welcomeSub}>
                  You're currently being served by the
                  <span style={styles.versionBadge}> Canary v{version} </span>
                  deployment. Help us improve by sharing your experience.
                </p>
              </div>
            </div>
            <div style={styles.versionTag}>
              {weight !== null && (
                <div style={styles.trafficMeter}>
                  <div style={styles.meterLabel}>Canary traffic slice</div>
                  <div style={styles.meterValue}>{weight}%</div>
                  <div className="progress-bar-wrap" style={{ width: 140 }}>
                    <div
                      className="progress-bar-fill"
                      style={{
                        width: `${weight}%`,
                        background: "linear-gradient(90deg, var(--purple), var(--accent))",
                      }}
                    />
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Feedback section */}
          <div style={styles.feedbackRow}>

            {/* Feedback buttons */}
            <div className="card anim-fade-up" style={{ ...styles.feedbackCard, animationDelay: "0.1s" }}>
              <h2 style={styles.sectionTitle}>
                <span>💬</span> Share Your Feedback
              </h2>
              <p style={styles.sectionSub}>
                How is your experience with this version? Your feedback helps the team decide whether to promote the canary.
              </p>

              <div style={styles.btnGroup}>
                <button
                  id="feedback-good-btn"
                  className="btn btn-success"
                  style={styles.feedbackBtn}
                  onClick={() => sendFeedback("good")}
                  disabled={loading.good || loading.bad}
                >
                  {loading.good ? (
                    <span style={spinnerStyle} />
                  ) : (
                    <span style={styles.thumbIcon}>👍</span>
                  )}
                  <div>
                    <div style={styles.feedbackBtnTitle}>Looks Great!</div>
                    <div style={styles.feedbackBtnSub}>Everything works perfectly</div>
                  </div>
                </button>

                <button
                  id="feedback-bad-btn"
                  className="btn btn-danger"
                  style={styles.feedbackBtn}
                  onClick={() => sendFeedback("bad")}
                  disabled={loading.good || loading.bad}
                >
                  {loading.bad ? (
                    <span style={spinnerStyle} />
                  ) : (
                    <span style={styles.thumbIcon}>👎</span>
                  )}
                  <div>
                    <div style={styles.feedbackBtnTitle}>Something's Wrong</div>
                    <div style={styles.feedbackBtnSub}>Report an issue</div>
                  </div>
                </button>
              </div>

              {/* Live tally */}
              <div style={styles.tallyRow}>
                <div style={styles.tallyItem}>
                  <span style={{ color: "var(--green)", fontSize: 18 }}>👍</span>
                  <span style={styles.tallyNum}>{stats.good}</span>
                  <span style={styles.tallyLabel}>positive</span>
                </div>
                <div style={styles.tallySep} />
                <div style={styles.tallyItem}>
                  <span style={{ color: "var(--red)", fontSize: 18 }}>👎</span>
                  <span style={styles.tallyNum}>{stats.bad}</span>
                  <span style={styles.tallyLabel}>negative</span>
                </div>
                <div style={styles.tallySep} />
                <div style={styles.tallyItem}>
                  <span style={{ fontSize: 18 }}>📊</span>
                  <span style={styles.tallyNum}>{total}</span>
                  <span style={styles.tallyLabel}>total</span>
                </div>
              </div>

              {total > 0 && (
                <div style={{ marginTop: 8 }}>
                  <div style={styles.barLabels}>
                    <span style={{ color: "var(--green)", fontSize: 12, fontWeight: 600 }}>{goodPct}% positive</span>
                    <span style={{ color: "var(--red)", fontSize: 12, fontWeight: 600 }}>{badPct}% negative</span>
                  </div>
                  <div style={styles.splitBar}>
                    <div style={{ width: `${goodPct}%`, background: "var(--green)", height: "100%", borderRadius: "4px 0 0 4px", transition: "width 0.6s ease" }} />
                    <div style={{ width: `${badPct}%`, background: "var(--red)", height: "100%", borderRadius: "0 4px 4px 0", transition: "width 0.6s ease" }} />
                  </div>
                </div>
              )}
            </div>

            {/* Docker concept panel */}
            <div className="card anim-fade-up" style={{ ...styles.dockerCard, animationDelay: "0.2s" }}>
              <h2 style={styles.sectionTitle}>
                <span>🐳</span> Docker Deployment
              </h2>
              <p style={styles.sectionSub}>
                Your request was handled by one of these containers. The ingress routes based on the canary weight.
              </p>

              <div style={styles.containers}>
                {/* Stable container */}
                <div style={styles.containerBox}>
                  <div style={styles.containerHeader}>
                    <span style={styles.containerIcon}>🟢</span>
                    <div>
                      <div style={styles.containerName}>nginx-stable</div>
                      <div style={styles.containerTag}>v1.0.0 · Production</div>
                    </div>
                    <div className="badge badge-green">Stable</div>
                  </div>
                  <div style={styles.containerMeta}>
                    <div style={styles.metaRow}><span className="mono" style={styles.metaKey}>IMAGE</span><span className="mono" style={styles.metaVal}>nginx:1.0.0</span></div>
                    <div style={styles.metaRow}><span className="mono" style={styles.metaKey}>PORT</span><span className="mono" style={styles.metaVal}>80/tcp</span></div>
                    <div style={styles.metaRow}><span className="mono" style={styles.metaKey}>TRAFFIC</span><span className="mono" style={{ ...styles.metaVal, color: "var(--green)" }}>{weight !== null ? 100 - weight : 80}%</span></div>
                  </div>
                  <div style={styles.trafficBar}>
                    <div style={{ ...styles.trafficFill, width: weight !== null ? `${100 - weight}%` : "80%", background: "var(--green)" }} />
                  </div>
                </div>

                {/* Canary container */}
                <div style={{ ...styles.containerBox, borderColor: "rgba(139,92,246,0.4)", boxShadow: "0 0 20px rgba(139,92,246,0.12)" }}>
                  <div style={styles.containerHeader}>
                    <span style={styles.containerIcon}>🟣</span>
                    <div>
                      <div style={styles.containerName}>nginx-canary</div>
                      <div style={styles.containerTag}>v2.0.0 · Canary</div>
                    </div>
                    <div className="badge badge-purple">Canary</div>
                  </div>
                  <div style={styles.containerMeta}>
                    <div style={styles.metaRow}><span className="mono" style={styles.metaKey}>IMAGE</span><span className="mono" style={styles.metaVal}>nginx:2.0.0</span></div>
                    <div style={styles.metaRow}><span className="mono" style={styles.metaKey}>PORT</span><span className="mono" style={styles.metaVal}>80/tcp</span></div>
                    <div style={styles.metaRow}><span className="mono" style={styles.metaKey}>TRAFFIC</span><span className="mono" style={{ ...styles.metaVal, color: "var(--purple)" }}>{weight !== null ? weight : 20}%</span></div>
                  </div>
                  <div style={styles.trafficBar}>
                    <div style={{ ...styles.trafficFill, width: weight !== null ? `${weight}%` : "20%", background: "var(--purple)" }} />
                  </div>
                </div>
              </div>

              {/* Health */}
              <div style={styles.healthRow}>
                <span style={{ fontSize: 13, color: "var(--text-muted)" }}>Backend status:</span>
                {health === "ok"
                  ? <div className="badge badge-green"><span className="dot dot-green" /> Healthy</div>
                  : <div className="badge badge-red"><span className="dot dot-red" /> Offline</div>}
              </div>
            </div>
          </div>
        </main>
      </div>
    </>
  );
}

